package com.agent.drift.api.impl;  import com.agent.drift.enums.DriftType; import com.agent.drift.model.DriftSignal; import org.junit.jupiter.api.DisplayName; import org.junit.jupiter.api.Test;  import static org.assertj.core.api.Assertions.assertThat;  /**  * {@link DriftDetectorImpl} 单元测试。  */ class DriftDetectorImplTest {      private final DriftDetectorImpl detector = new DriftDetectorImpl();      @Test     @DisplayName("行为漂移: score 超阈值 → BEHAVIOR_DRIFT")     void shouldDetectBehaviorDrift() {         DriftSignal signal = new DriftSignal(DriftType.BEHAVIOR_DRIFT, 0.35, 0.20);         assertThat(detector.detect(signal)).isEqualTo(DriftType.BEHAVIOR_DRIFT);     }      @Test     @DisplayName("效果漂移: score 超阈值 → EFFECT_DRIFT")     void shouldDetectEffectDrift() {         DriftSignal signal = new DriftSignal(DriftType.EFFECT_DRIFT, 0.5, 0.3);         assertThat(detector.detect(signal)).isEqualTo(DriftType.EFFECT_DRIFT);     }      @Test     @DisplayName("对齐漂移: cosine 低于阈值 → ALIGNMENT_DRIFT")     void shouldDetectAlignmentDrift() {         DriftSignal signal = new DriftSignal(DriftType.ALIGNMENT_DRIFT, 0.0, 0.8);         signal.setAlignmentCosine(0.5);         assertThat(detector.detect(signal)).isEqualTo(DriftType.ALIGNMENT_DRIFT);     }      @Test     @DisplayName("记忆漂移: 相关性下降比例超阈值 → MEMORY_DRIFT")     void shouldDetectMemoryDrift() {         DriftSignal signal = new DriftSignal(DriftType.MEMORY_DRIFT, 0.0, 0.3);         signal.setRelevanceDeclineRatio(0.5);         assertThat(detector.detect(signal)).isEqualTo(DriftType.MEMORY_DRIFT);     }      @Test     @DisplayName("score 未超阈值 / null 信号 / type 为 null 或 NONE → NONE")     void shouldReturnNoneWhenNoDrift() {         DriftSignal below = new DriftSignal(DriftType.BEHAVIOR_DRIFT, 0.10, 0.20);         assertThat(detector.detect(below)).isEqualTo(DriftType.NONE);         assertThat(detector.detect(null)).isEqualTo(DriftType.NONE);          DriftSignal nullType = new DriftSignal();         assertThat(detector.detect(nullType)).isEqualTo(DriftType.NONE);          DriftSignal noneType = new DriftSignal(DriftType.NONE, 0.5, 0.2);         assertThat(detector.detect(noneType)).isEqualTo(DriftType.NONE);     } }